!function(){try{var e="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{},i=(new e.Error).stack;i&&(e._sentryDebugIds=e._sentryDebugIds||{},e._sentryDebugIds[i]="2001fba8-e8a1-4358-a024-6417428a2a27",e._sentryDebugIdIdentifier="sentry-dbid-2001fba8-e8a1-4358-a024-6417428a2a27")}catch(e){}}();var _global="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{};_global.SENTRY_RELEASE={id:"endfield-returning-user-reward-web@1.0.0"},(self.webpackChunkendfield_returning_user_reward_web=self.webpackChunkendfield_returning_user_reward_web||[]).push([[791],{80791:function(e,i,a){a.r(i),a.d(i,{locale:function(){return n}});var o=a(23068),t=JSON.parse('{"title":"Protocollo di riconnessione","description":"Ti diamo il bentornato su Talos-II, Endministrator.","guide":{"character":"Perlica","lines":"Endmin, come sono andate le vacanze? A bordo della Dijiang sono successe un sacco di cose, e i nostri operatori della Divisione medica mi hanno ripetuto fino allo sfinimento di ricordarti di sottoporti all\'esame fisico! Manchi a tutti e... anche io ti sto aspettando, Endmin.","button":"Protocollo di riconnessione"},"home":{"title":"Protocollo di riconnessione","timeCount":"{{DD}} G {{HH}} H","tabs":{"checkIn":"Accesso per la riconnessione","task":"Incarichi di riconnessione","survey":"Sondaggio sul ritorno"},"checkIn":{"title":"Accesso per la riconnessione","intro":"Partecipa all\'evento di 7 giorni \\"Accesso per la riconnessione\\" per ottenere 2000 Oroberilli e altre ricompense!"},"task":{"intro":"Partecipa all\'evento \\"Incarichi di riconnessione\\" e completa i vari incarichi per ottenere <b>4 permessi CT base</b> e altre ricompense!","taskStatus":{"claimable":"Riscatta","ongoing":"Non completato","claimed":"Riscattato"},"claimAvailable":"Riscatta tutto","currentPoint":"Punti attuali","taskContent":{"daily_login":"Effettua l\'accesso al gioco 1 volta al giorno (può essere completato 7 volte).","deploy_factory":"Posiziona una struttura qualsiasi della fabbrica del SIA.","battle_enemy":"Sconfiggi 10 nemici qualsiasi.","clear_stage":"Completa un qualsiasi spazio protocollare 1 volta.","manufacture":"Recupera i prodotti da una cabina di produzione qualsiasi della Dijiang 1 volta.","upgrade_role_level":"Fai salire di livello un operatore qualsiasi 1 volta.","collect_ore":"Raccogli un minerale qualsiasi 1 volta.","trade_goods":"Scambia articoli con un avamposto qualsiasi 1 volta.","buy_goods":"Acquista articoli da un sistema di ridistribuzione scorte qualsiasi 1 volta.","trade_credit":"Acquista articoli dal negozio Crediti 1 volta.","collect_item":"Raccogli 8 boleti rosa.","ap_cost":"Spendi 1000 punti Lucidità.","boss_challenge":"Completa una qualsiasi sfida RE-Crisi 1 volta.","world_battle":"Risana sedimenti energetici 1 volta (valgono anche i sedimenti energetici temporanei)"}},"minimumTimeCount":"<1 H","survey":{"surveyStatus":{"not_started":"Non ancora iniziato","claimed":"Completato"},"goToButton":"Vai","unlockText":"Si sblocca tra: {{timeCount}}","rewardTip":"Completa il sondaggio per ottenere","surveyContent":{"survey_1":"Sondaggio sul primo giorno del ritorno","survey_2":"Sondaggio sull\'esperienza del ritorno"},"callbackModal":{"title":"NOTIFICA DI SISTEMA","content":"Vai alla nuova pagina per partecipare al sondaggio.","button":"Fatto"}}},"rule":{"title":"Dettagli evento \\"Protocollo di riconnessione\\"","content":"<b>- Requisiti per partecipare -</b>\\n<span>· Livello di autorità dell\'Endministrator ≥ 3.</span>\\n<span>· Aver completato la missione principale \\"Capitolo I - Elaborazione I: Elettricità per la Valle\\".</span>\\n<span>· Non aver effettuato l\'accesso al gioco per 21 o più giorni consecutivi.</span>\\n<span>· 42 o più giorni trascorsi dall\'ultima partecipazione all\'evento \\"Protocollo di riconnessione\\".</span>\\n<span>· La durata dello stato Ritorno dell\'Endministrator è la stessa dell\'evento \\"Protocollo di riconnessione\\".</span>\\n\\n<b>- Regole evento -</b>\\n<span>Visitare la pagina \\"Protocollo di riconnessione\\" per la prima volta fornisce una ricompensa Protocollo di riconnessione, Endministrator.</span>\\n<span>· Durante l\'evento, vai alla pagina \\"Protocollo di riconnessione\\" e partecipa ad \\"Accesso per la riconnessione\\" e \\"Incarichi di riconnessione\\" per ottenere ricompense.</span>\\n<span>· Durante l\'evento, effettua accessi di \\"Accesso per la riconnessione\\" ogni giorno per ottenere ricompense. È possibile effettuare accessi giornalieri 7 volte.</span>\\n<span>· Durante l\'evento, completa vari \\"Incarichi di riconnessione\\" per ottenere punti evento e ricompense. Se guadagni abbastanza punti, otterrai ricompense bonus.</span>\\n<span>Il conteggio dei dati per gli \\"Incarichi di riconnessione\\" potrebbe subire lievi ritardi. Una volta soddisfatti i requisiti dell\'incarico, attendi 2-5 minuti perché i dati vengano sincronizzati.</span>\\n<span>· Tutte le ricompense dell\'evento ti verranno recapitate nella posta di gioco. Il messaggio contenente la ricompensa scade dopo 30 giorni, quindi assicurati di riscattarla in tempo, Endministrator.</span>\\n<span>· L\'evento termina 14 giorni dopo la tua partecipazione e si chiude alle 04:00 (fuso orario del server).</span>"},"rewardModal":{"title":"Ricompense ottenute","prompt":"Queste ricompense sono state inviate alla tua posta: non dimenticarti di riscattarle, Endmin.","pointTitle":"Punti ottenuti","closeTip":"Fai clic per chiudere","closeTip_PC":"Fai clic per chiudere","closeTip_MB":"Tocca per chiudere"},"gameItem":{"item_gold":{"name":"Crediti-T","usage":"Nota anche come \\"CT\\", questa valuta è riconosciuta e utilizzata in molti luoghi.","desc":"Una valuta molto utilizzata e dotata di un\'avanzata tecnologia anti-contraffazione. Comunque, ciò che conta è che puoi usarla per fare acquisti."},"item_diamond":{"name":"Oroberillo","usage":"Un materiale artificiale spesso utilizzato per reclutare operatori.","desc":"Un prodotto speciale realizzato tagliando Origeometrie. Queste pietre sono molto amate per via della loro bellezza e versatilità."},"item_expcard_stage1_high":{"name":"Registrazione di combattimenti avanzata","usage":"Un materiale che conferisce molta esperienza per far salire gli operatori dal livello 1 al 60.","desc":"Un dispositivo di archiviazione che contiene le registrazioni di alcuni combattimenti, dalle quali i nuovi operatori possono trarre spunti utili. Sono incluse anche delle simulazioni di battaglie storiche che trasmettono tutta la brutalità delle guerre realmente combattute su Talos-II."},"item_weapon_expcard_high":{"name":"Set per ispezione armi","usage":"Un materiale che conferisce molta esperienza per le armi.","desc":"Dotato della tecnologia del SIA, questo set di strumenti monouso esegue un\'approfondita ispezione automatica dell\'intera struttura dell\'arma, riparandone i danni materiali interni e aumentandone di molto l\'efficacia."},"item_char_break_stage_1_2":{"name":"Protodisco","usage":"Un materiale che promuove gli operatori a E1 o E2.","desc":"Un disco speciale creato tramite tecno-protocollo e processi standard di scrittura dei dati. Viene spesso usato in combinazione con altri dispositivi per alleviare l\'affaticamento degli operatori durante l\'allenamento."},"item_ticketgacha_standard_single":{"name":"Permesso CT base","usage":"Un certificato interno della Endfield Industries. Usalo per effettuare 1 caccia ai talenti nella caccia ai talenti base.","desc":"La Endfield Industries ha molti contatti e una gran quantità di risorse in tutta Talos-II. Quando le risorse umane vanno a caccia di talenti in un particolare settore, c\'è sempre chi risponde alla chiamata."},"ap_supply_lt_n":{"name":"Potenziamento di Lucidità d\'emergenza","usage":"Usa quest\'oggetto per recuperare 40 punti Lucidità, ma ricorda che ha una data di scadenza!","desc":"Una dose moderata di sciroppo per la Lucidità contenuta in una confezione per le emergenze. A quanto pare, chi l\'ha sviluppata ha scoperto una formula segreta in alcuni strani documenti che moltiplicava la quantità di zucchero di questa particolare preparazione."},"item_bp_double_reward":{"name":"Permesso d\'uso di Lucidità","usage":"Usa questo oggetto per raddoppiare il consumo di Lucidità e riscattare il doppio delle ricompense nelle modalità di gioco che prevedono il consumo di Lucidità. Bisogna utilizzare 1 permesso ogni 10 punti Lucidità consumati.","desc":"Un permesso che consuma immediatamente una grande quantità di Lucidità. Il consumo eccessivo di Lucidità nuoce gravemente al corpo umano. Prima di procedere, dovrai sottoporti a una visita completa presso la Divisione medica."},"item_char_break_stage_3_4":{"name":"Protoset","usage":"Un materiale che promuove gli operatori a E3 o E4.","desc":"Un disco speciale creato tramite tecno-protocollo e processi avanzati di scrittura dei dati. Viene spesso usato in combinazione con altri dispositivi per alleviare l\'affaticamento degli operatori durante l\'allenamento."},"item_expcard_stage2_high":{"name":"Vettore cognitivo avanzato","usage":"Un materiale che conferisce molta esperienza per far salire gli operatori dal livello 61 al 90.","desc":"Un\'unità di archiviazione dati sviluppata dalla Endfield Industries, compatibile con un\'ampia varietà di dispositivi per la lettura di dati. I nuovi operatori possono usarla per apprendere nuove tattiche di combattimento. Essendo dotato di una tecnologia di compressione dati (cortesia della Cabala della Tranquillità), questo vettore contiene ancora più informazioni."},"item_weapon_break_high":{"name":"Matrice per pressofusione pesante","usage":"Un materiale che ottimizza le armi.","desc":"Una matrice per pressofusione pesante fabbricata con materiali rari. L\'attivazione tramite tecno-protocollo consente alla matrice di rafforzare le proprietà strutturali delle armi."},"item_char_skill_level_7_12":{"name":"Protoedro","usage":"Un materiale che potenzia le abilità degli operatori.","desc":"Un poliedro di cristallo speciale creato tramite tecno-protocollo e processi avanzati di cristallizzazione. Viene spesso usato in combinazione con altri dispositivi per migliorare l\'assorbimento fisiologico dei materiali migliorati."},"item_case_bp_selfselect_skillsp_1":{"name":"Cassa a scelta di sviluppo avanzato Ⅰ","usage":"Aprendola, puoi scegliere un materiale di sviluppo avanzato a tua scelta.","desc":"Una cassa che contiene materiali di alta qualità per impieghi generali. Le prestazioni in combattimento non sono una mera questione di genetica o esperienza: a volte basta solo un pizzico d\'ispirazione."}},"errMsg":{"code_2000":"Impossibile inviare le ricompense. Attendi e riprova.","rewardClaimed":"Questa ricompensa è già stata riscattata.","code_1002":"L\'evento è in caricamento. Attendi un momento prima di accedere di nuovo alla schermata dell\'evento.","code_1003":"L\'evento è terminato.","networkError":"Errore del servizio"},"gamepad":{"hint":{"confirm":"Conferma","close":"Off","closeCurrent":"Chiudi la schermata","exit":"Esci dalla pagina"}}}'),n={lang:o.ELanguage["it-it"],text:t,fonts:{}}}}]);
